import { Card, CardContent, CardHeader } from '@material-ui/core'
import React from 'react'

export default function StudentActivities({ activity }) {
  return (
    <div>
        <Card>
            <CardHeader title={activity.title} />
            <CardContent title={activity.body} />
        </Card>
    </div>
  )
}
